// Without variables:
console.log(10 + 10);
console.log(10 * 2);

// With variables:
let x = 10;
console.log(x + x);
console.log(x * 2);

// Mistake: Using before declaration
console.log(x);
let x = 10;

// Mistake: Case sensitivity
